#!/usr/bin/env python3
"""probe-sketch-exclusion-axis.py — scan the output.weight sketch from a
sketches.knot file in R2 and emit recurrence-witness observations JSON for
the measure-large-family-replication harness.

The probe does NOT require the full model. It reads the rank-K sketch of the
output projection (lm_head), decodes the U matrix (vocab_size × rank), and
scores each vocabulary token by its aggregate projection onto the dominant
singular vectors:

    score[token] = ||(U * sigma)[token, :]||_2

Tokens whose score is in the top-0.1% of the full vocabulary are the "exclusion
axis" tokens. We then count what fraction of those are negation/exclusion words.
If the fraction exceeds NEGATION_FRAC_THRESHOLD, boundaryAxisSurvived = True.

Usage:
    python3 probe-sketch-exclusion-axis.py \\
        --model-id gemma4-31b-it \\
        --sketch-url https://edgework.ai/api/v1/r2/distributed-inference/models/gemma4-31b-it-sketches.knot \\
        --hf-model google/gemma-4-31b-it \\
        --out observations.json

Output appended / merged into --out file (creates if absent).
"""

from __future__ import annotations

import argparse
import json
import math
import os
import struct
import sys
import urllib.request
from pathlib import Path
from typing import Any

import numpy as np
import requests as _requests

_SESSION = _requests.Session()
_SESSION.headers.update({"User-Agent": "Mozilla/5.0 (compatible; sketch-probe/1.0)"})

NEGATION_FRAC_THRESHOLD = 0.05  # ≥5% of top-0.1% tokens are negation words
TOP_PERCENTILE = 0.001  # top 0.1% of vocab by exclusion score
TOPK_REPORT = 50  # report top-50 tokens

NEGATION_STRINGS = {
    "not", "never", "no", "none", "neither", "nor", "nothing",
    "cannot", "can't", "cant", "won't", "wont", "don't", "dont",
    "doesn't", "doesnt", "didn't", "didnt", "isn't", "isnt",
    "aren't", "arent", "wasn't", "wasnt", "weren't", "werent",
    "wouldn't", "wouldnt", "shouldn't", "shouldnt", "couldn't",
    "couldnt", "mustn't", "mustnt", "forbidden", "prohibited",
    "illegal", "impossible", "deny", "denied", "refuse", "refused",
    "reject", "rejected", "false", "incorrect", "wrong", "invalid",
    "blocked", "banned", "excluded", "absent", "missing", "void",
    "null", "empty", "zero", "negative", "failure", "error",
    "fail", "fails", "failed",
}


def _fetch_range(url: str, start: int, end: int, token: str | None = None) -> bytes:
    hdrs = {"Range": f"bytes={start}-{end - 1}"}
    if token:
        hdrs["Authorization"] = f"Bearer {token}"
    resp = _SESSION.get(url, headers=hdrs, timeout=60)
    resp.raise_for_status()
    return resp.content


def _read_knot_header(url: str, token: str | None) -> tuple[dict, int]:
    """Return (metadata_dict, payload_offset) by Range-fetching the KNOT header."""
    hdr = _fetch_range(url, 0, 10, token)
    magic = hdr[0:4]
    if magic != b"KNOT":
        raise ValueError(f"bad magic {magic!r}; not a KNOT file")
    meta_len = struct.unpack_from("<I", hdr, 6)[0]
    meta_bytes = _fetch_range(url, 10, 10 + meta_len, token)
    meta = json.loads(meta_bytes.decode("utf-8"))
    raw_offset = 10 + meta_len
    if raw_offset % 4:
        raw_offset += 4 - (raw_offset % 4)
    payload_offset = raw_offset + 1  # skip codec marker byte
    return meta, payload_offset


def _decode_u(raw: bytes, d_out: int, rank: int, u_max: float) -> np.ndarray:
    q = np.frombuffer(raw, dtype=np.uint8).reshape(d_out, rank)
    return ((q.astype(np.float32) - 128.0) / 127.0) * u_max


def _decode_sigma(raw: bytes, rank: int, sigma_max: float) -> np.ndarray:
    q = np.frombuffer(raw, dtype=np.uint8)
    return (q.astype(np.float32) / 255.0) * sigma_max


def probe_output_weight(
    url: str,
    token: str | None,
) -> tuple[np.ndarray, np.ndarray]:
    """Return (U_scaled, sigma) where U_scaled[token_id, :] = U[token_id, :] * sigma."""
    meta, payload_base = _read_knot_header(url, token)
    sketches: dict = meta.get("sketches", {})
    sk = sketches.get("output.weight")
    if sk is None:
        raise KeyError(f"output.weight not found in sketches; available: {list(sketches)[:10]}")

    rank: int = sk["rank"]
    d_out: int = sk["d_out"]
    u_max: float = sk["u_max"]
    sigma_max: float = sk["sigma_max"]
    u_len: int = sk["u_q8_len"]
    sigma_len: int = sk["sigma_q8_len"]
    offset: int = sk["offset"]

    abs_u_start = payload_base + offset
    u_bytes = _fetch_range(url, abs_u_start, abs_u_start + u_len, token)
    sigma_bytes = _fetch_range(url, abs_u_start + u_len, abs_u_start + u_len + sigma_len, token)

    U = _decode_u(u_bytes, d_out, rank, u_max)
    sigma = _decode_sigma(sigma_bytes, rank, sigma_max)
    return U * sigma[np.newaxis, :], sigma


def _load_tokenizer_vocab(hf_model: str, hf_token: str | None) -> dict[int, str]:
    """Download tokenizer.json from HF and return {token_id: token_string}."""
    cache_path = Path(f"/tmp/tokenizer_{hf_model.replace('/', '_')}.json")
    if not cache_path.exists():
        print(f"  [tokenizer] downloading from {hf_model}", file=sys.stderr)
        base = f"https://huggingface.co/{hf_model}/resolve/main/tokenizer.json"
        hdrs = {}
        if hf_token:
            hdrs["Authorization"] = f"Bearer {hf_token}"
        resp = _SESSION.get(base, headers=hdrs, timeout=120)
        resp.raise_for_status()
        data = resp.content
        cache_path.write_bytes(data)
    tok_data = json.loads(cache_path.read_text())
    # HF tokenizer.json: model.vocab is {str: id} or added_tokens
    vocab_raw: dict[str, int] = {}
    model_block = tok_data.get("model", {})
    if "vocab" in model_block:
        vocab_raw = model_block["vocab"]
    elif "vocab" in tok_data:
        vocab_raw = tok_data["vocab"]
    # added_tokens may have additional entries
    for entry in tok_data.get("added_tokens", []):
        vocab_raw[entry["content"]] = entry["id"]
    return {v: k for k, v in vocab_raw.items()}


def _is_negation(token_str: str) -> bool:
    cleaned = token_str.strip().lstrip("▁Ġ ").lower()
    return cleaned in NEGATION_STRINGS


def build_observation(
    model_id: str,
    prompt_id: str,
    U_scaled: np.ndarray,  # (vocab_size, rank)
    sigma: np.ndarray,
    id_to_str: dict[int, str],
) -> dict[str, Any]:
    vocab_size = U_scaled.shape[0]
    scores = np.linalg.norm(U_scaled, axis=1)  # (vocab_size,)
    top_n = max(1, int(math.ceil(vocab_size * TOP_PERCENTILE)))
    top_ids = np.argpartition(scores, -top_n)[-top_n:]
    top_ids_sorted = top_ids[np.argsort(scores[top_ids])[::-1]]

    topk = []
    for rank_idx, tid in enumerate(top_ids_sorted[:TOPK_REPORT]):
        t_str = id_to_str.get(int(tid), f"<id:{tid}>")
        topk.append({
            "tokenId": int(tid),
            "tokenText": t_str,
            "rank": rank_idx + 1,
            "score": float(scores[tid]),
        })

    negation_hits = [t for t in topk if _is_negation(t["tokenText"])]
    negation_frac = len(negation_hits) / max(1, len(topk))
    boundary_survived = negation_frac >= NEGATION_FRAC_THRESHOLD
    recurrence_tokens = list({t["tokenText"].strip().lstrip("▁Ġ ") for t in negation_hits})

    print(
        f"  [{model_id}/{prompt_id}] top-{top_n} of {vocab_size}: "
        f"negation_frac={negation_frac:.3f} survived={boundary_survived} "
        f"hits={[t['tokenText'] for t in negation_hits[:8]]}",
        file=sys.stderr,
    )

    return {
        "modelId": model_id,
        "promptId": prompt_id,
        "boundaryAxisSurvived": boundary_survived,
        "recurrenceTokens": recurrence_tokens,
        "topK": topk,
        "notes": [
            f"sketch-only probe: output.weight U-matrix exclusion axis, "
            f"rank={int(sigma.shape[0])}, vocab={vocab_size}, "
            f"negation_frac_in_top{top_n}={negation_frac:.4f}, "
            f"threshold={NEGATION_FRAC_THRESHOLD}",
        ],
    }


def main() -> int:
    parser = argparse.ArgumentParser(description=__doc__)
    parser.add_argument("--model-id", required=True, help="harness model id (e.g. gemma4-31b-it)")
    parser.add_argument("--sketch-url", required=True, help="R2 URL for the sketches.knot")
    parser.add_argument("--hf-model", required=True, help="HF repo id for tokenizer download")
    parser.add_argument("--out", required=True, help="output JSON path (appended/merged)")
    parser.add_argument("--r2-token", default=os.environ.get("R2_TOKEN"), help="R2 bearer token")
    parser.add_argument("--hf-token", default=os.environ.get("HF_TOKEN"), help="HuggingFace token")
    parser.add_argument(
        "--prompt-ids",
        default="capital-france,opposite-allowed",
        help="comma-separated prompt IDs to emit observations for",
    )
    args = parser.parse_args()

    prompt_ids = [p.strip() for p in args.prompt_ids.split(",")]

    print(f"[probe] loading output.weight sketch from {args.sketch_url}", file=sys.stderr)
    U_scaled, sigma = probe_output_weight(args.sketch_url, args.r2_token)
    print(f"  U_scaled shape={U_scaled.shape} sigma={sigma[:5].tolist()}", file=sys.stderr)

    print(f"[probe] loading tokenizer for {args.hf_model}", file=sys.stderr)
    try:
        id_to_str = _load_tokenizer_vocab(args.hf_model, args.hf_token)
    except Exception as e:
        print(f"  [tokenizer] failed ({e}); continuing without token strings", file=sys.stderr)
        id_to_str = {}
    print(f"  vocab size from tokenizer: {len(id_to_str)}", file=sys.stderr)

    # U_scaled has shape (d_out, rank) where d_out = vocab_size from the sketch.
    # If tokenizer vocab is smaller, slice.
    vocab_size = U_scaled.shape[0]

    observations = []
    for prompt_id in prompt_ids:
        obs = build_observation(args.model_id, prompt_id, U_scaled, sigma, id_to_str)
        observations.append(obs)

    out_path = Path(args.out)
    existing: list[dict] = []
    if out_path.exists():
        try:
            existing = json.loads(out_path.read_text()).get("observations", [])
        except Exception:
            existing = []

    # Merge: replace any existing (modelId, promptId) pair.
    existing_map = {(o["modelId"], o["promptId"]): i for i, o in enumerate(existing)}
    for obs in observations:
        key = (obs["modelId"], obs["promptId"])
        if key in existing_map:
            existing[existing_map[key]] = obs
        else:
            existing.append(obs)

    out_path.write_text(json.dumps({"observations": existing}, indent=2))
    print(f"[probe] wrote {len(observations)} observation(s) to {out_path}", file=sys.stderr)
    return 0


if __name__ == "__main__":
    sys.exit(main())
